#!/usr/bin/env bash
# Twin Peaks Viewer — Mac / Linux / WSL
# Run:  bash run_dronology.sh
set -euo pipefail

WORK=$(mktemp -d)
trap 'rm -rf "$WORK"' EXIT

echo ""
echo "╔══════════════════════════════════════════════════════╗"
echo "║           Twin Peaks Viewer                          ║"
echo "╚══════════════════════════════════════════════════════╝"
echo ""
echo "  Extracting viewer..."

base64 -d > "$WORK/index.html" << 'TPEOF_HTML'

TPEOF_HTML

base64 -d > "$WORK/primary.json" << 'TPEOF_PRIMARY'

TPEOF_PRIMARY

base64 -d > "$WORK/vs.json" << 'TPEOF_VS'

TPEOF_VS

echo "  ✓ Ready."
echo ""
echo "  Open your browser and go to:"
echo ""
echo "      http://localhost:8080"
echo ""
echo "  Press Ctrl+C to stop."
echo ""

cd "$WORK"
python3 -m http.server 8080 > /dev/null 2>&1
